import{_ as a,o as r,c as o,a0 as n}from"./chunks/framework.DV6pVIgV.js";const p=JSON.parse('{"title":"雲端資料庫","description":"","frontmatter":{},"headers":[],"relativePath":"clf-c02/10.md","filePath":"clf-c02/10.md","lastUpdated":1783610848000}'),e={name:"clf-c02/10.md"};function s(d,t,l,i,g,h){return r(),o("div",null,[...t[0]||(t[0]=[n(`<h1 id="雲端資料庫" tabindex="-1">雲端資料庫 <a class="header-anchor" href="#雲端資料庫" aria-label="Permalink to &quot;雲端資料庫&quot;">​</a></h1><p>關聯式 vs NoSQL、RDS／Aurora、DynamoDB、快取與資料倉儲。</p><h2 id="先備知識" tabindex="-1">先備知識 <a class="header-anchor" href="#先備知識" aria-label="Permalink to &quot;先備知識&quot;">​</a></h2><ul><li><p><strong>SQL</strong></p><ul><li><a href="https://cwhu.medium.com/table-plus-sql-and-nosql-tutorial-d221cf3c7c22" target="_blank" rel="noreferrer">認識關聯式資料庫 RDBMS 與 NoSQL</a></li></ul></li><li><p><strong>NoSQL</strong></p><ul><li><a href="https://aws.amazon.com/tw/compare/the-difference-between-mongodb-vs-mysql/" target="_blank" rel="noreferrer">SQL vs NoSQL 用簡單範例看差異</a></li></ul></li><li><p><strong>PostgreSQL</strong></p><ul><li><a href="https://aws.amazon.com/tw/rds/postgresql/what-is-postgresql/" target="_blank" rel="noreferrer">什麼是 PostgreSQL？（AWS，繁中）</a></li></ul></li><li><p><strong>快取（Cache</strong> 🔍 任一篇「快取 cache 是什麼」入門即可</p></li></ul><h2 id="關聯式-vs-非關聯式-nosql" tabindex="-1">關聯式 vs 非關聯式（NoSQL） <a class="header-anchor" href="#關聯式-vs-非關聯式-nosql" aria-label="Permalink to &quot;關聯式 vs 非關聯式（NoSQL）&quot;">​</a></h2><p><strong>關聯式資料庫（Relational / SQL）</strong>：資料放在資料表裡，每張表有固定的欄位（Schema），表格之間可以建立關聯（如「訂單表」用顧客編號連到「顧客表」），用 SQL 查詢。</p><p>像一本嚴謹的帳本——每一列都要照規矩填、欄位不能亂來，不同表格用編號互相對應。這種「嚴格 + 有關聯」的特性，讓它非常適合結構固定、彼此有關係、且不能出錯的資料：銀行交易、訂單系統、庫存。</p><p><strong>非關聯式資料庫（NoSQL）</strong>：不要求固定 Schema，每一筆資料的結構可以不一樣；多半用「鍵 → 值」或「文件」方式存取，通常不做複雜的跨表關聯。</p><p>像一本可以隨意貼便利貼的筆記本——每張想寫什麼欄位都行，不必統一格式。犧牲嚴謹與關聯能力，換來<strong>極大規模的水平擴展與彈性</strong>。適合海量、結構多變、以簡單查找為主的場景：IoT 裝置資料、購物車、使用者 Session。</p><table tabindex="0"><thead><tr><th></th><th>關聯式（SQL）</th><th>非關聯式（NoSQL）</th></tr></thead><tbody><tr><td><strong>結構</strong></td><td>嚴格 Schema，資料表（列 + 欄）</td><td>彈性，每筆可不同</td></tr><tr><td><strong>關聯</strong></td><td>表格之間有關聯</td><td>通常無複雜關聯</td></tr><tr><td><strong>查詢</strong></td><td>SQL</td><td>各家自己的 API</td></tr><tr><td><strong>擴展</strong></td><td>寫入偏垂直；讀取可用 Read Replica 水平分擔</td><td>偏水平（海量分散）</td></tr><tr><td><strong>適合</strong></td><td>結構化、有關聯、交易（銀行、訂單）</td><td>海量、彈性、簡單查找（遊戲、IoT）</td></tr><tr><td><strong>AWS 服務</strong></td><td>RDS、Aurora</td><td>DynamoDB</td></tr></tbody></table><blockquote><p>📌 資料結構固定、彼此有關聯、需要交易正確性 → 關聯式（RDS / Aurora）；海量規模、結構彈性、簡單快速查找 → NoSQL（DynamoDB）。</p></blockquote><h2 id="關聯式資料庫-amazon-rds-與-aurora" tabindex="-1">關聯式資料庫：Amazon RDS 與 Aurora <a class="header-anchor" href="#關聯式資料庫-amazon-rds-與-aurora" aria-label="Permalink to &quot;關聯式資料庫：Amazon RDS 與 Aurora&quot;">​</a></h2><h3 id="amazon-rds-relational-database-service" tabindex="-1">Amazon RDS（Relational Database Service） <a class="header-anchor" href="#amazon-rds-relational-database-service" aria-label="Permalink to &quot;Amazon RDS（Relational Database Service）&quot;">​</a></h3><p>RDS 是託管的關聯式資料庫。「託管」的重點在於：如果自己在 EC2 上裝資料庫，你得負責安裝、打補丁、備份、設定故障切換——很繁瑣。RDS 把這些雜事接手了，你專注用資料庫本身就好。</p><p>RDS 支援多種引擎：MySQL、PostgreSQL、MariaDB、Oracle、SQL Server，以及 AWS 自家的 Aurora。</p><p><strong>兩個最常被搞混的機制：</strong></p><table tabindex="0"><thead><tr><th>機制</th><th>目的</th><th>怎麼運作</th></tr></thead><tbody><tr><td><strong>Multi-AZ</strong>（多可用區）</td><td>高可用 / 故障自動切換</td><td>在另一個 AZ 放一個 Standby（待命副本）；主資料庫故障時自動切換過去</td></tr><tr><td><strong>Read Replica</strong>（唯讀副本）</td><td>分擔讀取、提升讀效能</td><td>建立唯讀副本承接大量讀取流量</td></tr></tbody></table><p>Multi-AZ 的 Standby <strong>平常不對外服務</strong>，它唯一的任務就是「主機掛了我接手」——是為了高可用，不是用來分散讀取。</p><ul><li>想提升讀取效能 / 分散讀取 → <strong>Read Replica</strong></li><li>資料庫故障要自動切換不中斷 → <strong>Multi-AZ</strong></li></ul><h3 id="amazon-aurora" tabindex="-1">Amazon Aurora <a class="header-anchor" href="#amazon-aurora" aria-label="Permalink to &quot;Amazon Aurora&quot;">​</a></h3><p>Aurora 是 AWS 自己打造的關聯式資料庫，相容 MySQL 與 PostgreSQL，但效能與可用性更高：效能可達 MySQL 數倍，資料自動跨 3 個 AZ 存 6 份副本，儲存空間自動擴展。</p><p>可以把 Aurora 想成「RDS 家族裡的高階款」：要關聯式資料庫、又要更高效能與更強可用性，且能接受 MySQL / PostgreSQL 相容引擎時，選 Aurora。</p><h2 id="nosql-資料庫-amazon-dynamodb" tabindex="-1">NoSQL 資料庫：Amazon DynamoDB <a class="header-anchor" href="#nosql-資料庫-amazon-dynamodb" aria-label="Permalink to &quot;NoSQL 資料庫：Amazon DynamoDB&quot;">​</a></h2><p>DynamoDB 是完全託管的 NoSQL 資料庫（鍵值 / 文件型），特色是：</p><ul><li><strong>無伺服器（Serverless）</strong>：沒有伺服器要管、不用做容量規劃</li><li><strong>任何規模都維持毫秒的回應</strong>：流量從一千暴增到一千萬，效能依然穩定</li><li><strong>自動擴展、自動跨多 AZ 高可用</strong></li></ul><blockquote><p>💡 為什麼它能這麼快又這麼能擴展？因為它放棄了「跨表關聯 + 嚴格 Schema」的包袱，專注把「用鍵快速存取單筆資料」做到極致。代價是不適合需要複雜關聯查詢的場景。</p></blockquote><p>適合：遊戲狀態、IoT、行動 App 後端、購物車、使用者 Session——「海量、要快、結構單純」的典型。</p><h2 id="記憶體內快取-in-memory-caching" tabindex="-1">記憶體內快取（In-Memory Caching） <a class="header-anchor" href="#記憶體內快取-in-memory-caching" aria-label="Permalink to &quot;記憶體內快取（In-Memory Caching）&quot;">​</a></h2><p><strong>為什麼需要快取？</strong> 假設網站首頁要從資料庫撈「熱門商品」，每秒上萬人都來看同一份資料——每次都去查資料庫又慢又貴。解法是把這份熱資料放進記憶體，下次直接拿（微秒級），大幅減輕資料庫負擔。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>應用程式</span></span>
<span class="line"><span>    ↓ 先問快取（記憶體，微秒級）</span></span>
<span class="line"><span>ElastiCache ─── 有 → 直接回（超快，不打擾資料庫）</span></span>
<span class="line"><span>    ↓ 沒有（Cache Miss）</span></span>
<span class="line"><span>資料庫（RDS / DynamoDB）── 取出後存進快取，下次就有了</span></span></code></pre></div><table tabindex="0"><thead><tr><th>服務</th><th>是什麼</th><th>重點</th></tr></thead><tbody><tr><td><strong>Amazon ElastiCache</strong></td><td>託管的記憶體快取（Redis / Memcached）</td><td>把熱資料放記憶體、加速讀取、減輕資料庫負擔</td></tr><tr><td><strong>Amazon DynamoDB Accelerator（DAX）</strong></td><td>專給 DynamoDB 的記憶體快取</td><td>讓 DynamoDB 的讀取從毫秒再降到微秒</td></tr></tbody></table><hr><h2 id="其他資料庫服務" tabindex="-1">其他資料庫服務 <a class="header-anchor" href="#其他資料庫服務" aria-label="Permalink to &quot;其他資料庫服務&quot;">​</a></h2><p>不同用途的資料，有對應的專用資料庫：</p><table tabindex="0"><thead><tr><th>服務</th><th>類型</th><th>適合</th></tr></thead><tbody><tr><td><strong>Amazon Redshift</strong></td><td>資料倉儲</td><td>對海量歷史資料跑複雜分析、產報表（商業智慧 / BI）</td></tr><tr><td><strong>Amazon Neptune</strong></td><td>圖形資料庫</td><td>處理關係網絡：社群關係、推薦、詐騙偵測</td></tr><tr><td><strong>Amazon DocumentDB</strong></td><td>文件資料庫</td><td>相容 MongoDB 的文件型應用</td></tr><tr><td><strong>AWS DMS</strong>（Database Migration Service）</td><td>資料庫遷移</td><td>把資料庫搬到 AWS，過程盡量不中斷</td></tr></tbody></table><p>一般資料庫（RDS / DynamoDB）處理「日常交易」——一筆筆訂單、即時查詢，這類叫 OLTP（Online Transaction Processing，線上交易處理）；Redshift 是「<strong>資料倉儲</strong>」，把大量歷史資料集中起來跑複雜分析查詢，這類叫 OLAP（Online Analytical Processing，線上分析處理）。看到「資料倉儲、商業智慧、分析海量資料、產報表、OLAP」→ <strong>Redshift</strong>。</p><h2 id="考試重點整理" tabindex="-1">考試重點整理 <a class="header-anchor" href="#考試重點整理" aria-label="Permalink to &quot;考試重點整理&quot;">​</a></h2><ul><li><strong>第一刀分類</strong>：關聯式（嚴格 Schema、有關聯、SQL、交易）vs NoSQL（彈性、海量、鍵值查找）</li><li><strong>RDS</strong> = 託管關聯式資料庫，支援 MySQL / PostgreSQL / MariaDB / Oracle / SQL Server / Aurora；接手安裝、補丁、備份、故障切換</li><li>🚨 <strong>Multi-AZ vs Read Replica</strong>：Multi-AZ = 高可用 / 故障自動切換（Standby 平常不對外）；Read Replica = 分擔讀取 / 提升讀效能。別搞混</li><li><strong>Aurora</strong> = AWS 自家高階關聯式（相容 MySQL / PostgreSQL），效能高、跨 3 AZ 存 6 份</li><li>🚨 <strong>DynamoDB</strong> = 無伺服器 NoSQL，任何規模個位數毫秒、自動擴展、跨多 AZ；要 SQL / 關聯找 RDS，要海量鍵值找 DynamoDB</li><li><strong>快取</strong>：<strong>ElastiCache</strong>（Redis / Memcached，加速讀取、減輕資料庫）；<strong>DAX</strong>（專給 DynamoDB 的記憶體快取，降到微秒）</li><li>🚨 <strong>Redshift</strong> = 資料倉儲（OLAP）；RDS / DynamoDB 處理日常交易（OLTP）；看到「BI、分析海量歷史資料、OLAP」→ Redshift</li><li><strong>Neptune</strong>（圖形 / 關係網絡）、<strong>DocumentDB</strong>（文件 / MongoDB 相容）、<strong>DMS</strong>（資料庫遷移上雲）</li></ul><table tabindex="0"><thead><tr><th>情境需求</th><th>答案</th></tr></thead><tbody><tr><td>結構固定、有關聯、交易正確（訂單、銀行）</td><td><strong>RDS</strong></td></tr><tr><td>要關聯式、又要更高效能與可用性</td><td><strong>Aurora</strong></td></tr><tr><td>海量、彈性 Schema、極快鍵值查找、無伺服器</td><td><strong>DynamoDB</strong></td></tr><tr><td>資料庫故障要自動切換、不中斷</td><td><strong>RDS Multi-AZ</strong></td></tr><tr><td>想分擔讀取流量、提升讀效能</td><td><strong>RDS Read Replica</strong></td></tr><tr><td>加速重複讀取、減輕資料庫壓力</td><td><strong>ElastiCache</strong></td></tr><tr><td>加速 DynamoDB 的讀取（到微秒）</td><td><strong>DAX</strong></td></tr><tr><td>對海量資料跑分析、做 BI 報表</td><td><strong>Redshift</strong>（資料倉儲）</td></tr><tr><td>處理社群關係 / 推薦 / 詐騙這類關係網絡</td><td><strong>Neptune</strong>（圖形）</td></tr><tr><td>把現有資料庫搬上 AWS</td><td><strong>DMS</strong></td></tr></tbody></table>`,39)])])}const S=a(e,[["render",s]]);export{p as __pageData,S as default};
